function ColumnEditor({ columns, onChange }: Props) {
  const [editingColumn, setEditingColumn] = useState<Column | null>(null);
  
  const addColumn = () => {
    const newColumn: Column = {
      name: 'new_column',
      type: 'text',
      nullable: true,
      isPrimaryKey: false,
      isForeignKey: false,
      isUnique: false,
    };
    onChange([...columns, newColumn]);
  };
  
  const updateColumn = (index: number, updates: Partial<Column>) => {
    const updated = [...columns];
    updated[index] = { ...updated[index], ...updates };
    onChange(updated);
  };
  
  const deleteColumn = (index: number) => {
    onChange(columns.filter((_, i) => i !== index));
  };
  
  return (
    <div className="column-editor">
      <div className="editor-header">
        <h3>Columns</h3>
        <button onClick={addColumn}>
          <PlusIcon /> Add Column
        </button>
      </div>
      
      <table className="column-table">
        <thead>
          <tr>
            <th>Name</th>
            <th>Type</th>
            <th>Nullable</th>
            <th>PK</th>
            <th>FK</th>
            <th>Unique</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {columns.map((column, index) => (
            <tr key={index}>
              <td>
                <input
                  value={column.name}
                  onChange={(e) => updateColumn(index, { name: e.target.value })}
                />
              </td>
              <td>
                <select
                  value={column.type}
                  onChange={(e) => updateColumn(index, { type: e.target.value })}
                >
                  <option value="text">Text</option>
                  <option value="integer">Integer</option>
                  <option value="bigint">BigInt</option>
                  <option value="uuid">UUID</option>
                  <option value="timestamp">Timestamp</option>
                  <option value="boolean">Boolean</option>
                  <option value="json">JSON</option>
                </select>
              </td>
              <td>
                <input
                  type="checkbox"
                  checked={column.nullable}
                  onChange={(e) => updateColumn(index, { nullable: e.target.checked })}
                />
              </td>
              <td>
                <input
                  type="checkbox"
                  checked={column.isPrimaryKey}
                  onChange={(e) => updateColumn(index, { isPrimaryKey: e.target.checked })}
                />
              </td>
              <td>
                <input
                  type="checkbox"
                  checked={column.isForeignKey}
                  onChange={(e) => updateColumn(index, { isForeignKey: e.target.checked })}
                />
              </td>
              <td>
                <input
                  type="checkbox"
                  checked={column.isUnique}
                  onChange={(e) => updateColumn(index, { isUnique: e.target.checked })}
                />
              </td>
              <td>
                <button onClick={() => setEditingColumn(column)}>
                  <EditIcon />
                </button>
                <button onClick={() => deleteColumn(index)}>
                  <TrashIcon />
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
      
      {editingColumn && (
        <ColumnDetailModal
          column={editingColumn}
          onSave={(updated) => {
            const index = columns.findIndex(c => c.name === editingColumn.name);
            updateColumn(index, updated);
            setEditingColumn(null);
          }}
          onClose={() => setEditingColumn(null)}
        />
      )}
    </div>
  );
}
```

